<template>
  <div class="number-input" :class="props.canReset ? 'withReset' : ''">
    <label class="labelGrid" v-if="props.label">{{ label }} </label>

    <InputNumber
      :value="valueTodisplay"
      :step="props.step"
      :onChangeCallback="changeHandler"
    />
    <!-- <span class="unit">{{ props.unit }} </span> -->
  </div>
</template>

<script setup lang="ts">
import InputNumber from "@/DesignSystem/Form/InputNumber.vue";
import { computed } from "vue";
export interface InputProps {
  properties: { [key: string]: string };
  propertyName: string;
  id: string;
  label?: string;
  unit?: string;
  float?: boolean;
  step?: number;
  canReset?: boolean;
}
const props = withDefaults(defineProps<InputProps>(), {
  unit: "mm",
  float: false,
  step: 1,
  canReset: false,
  newProperties: Object,
});
// console.log(props.newProperties)
const valueTodisplay = computed(() => {
  const currentValue = props.properties[props.propertyName];
  if (!currentValue) {
    return undefined;
  }
  return props.float ? parseFloat(currentValue) : parseInt(currentValue);
});

function changeHandler(value: number) {
  // eslint-disable-next-line vue/no-mutating-props
  props.properties[props.propertyName] = value + props.unit;
}
</script>

